import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { authApi, auth } from '../services/api';

const S = {
  page: { display: 'flex', minHeight: 'calc(100vh - 64px)', background: 'var(--color-bg)' },
  left: {
    flex: 1, background: 'var(--color-dark)', padding: '64px 48px',
    display: 'flex', flexDirection: 'column', justifyContent: 'center', minWidth: 0,
  },
  right: {
    width: '56%', flexShrink: 0, padding: '48px',
    display: 'flex', flexDirection: 'column', justifyContent: 'center', overflowY: 'auto',
  },
  logo: { fontSize: 'var(--text-2xl)', fontWeight: 900, color: '#fff', marginBottom: 8, letterSpacing: '-0.02em' },
  logoDot: { color: 'var(--color-gold)', marginLeft: 2 },
  leftTitle: { fontSize: 'clamp(1.5rem,2.5vw,2.25rem)', fontWeight: 'var(--weight-bold)', color: '#fff', letterSpacing: '-0.02em', marginBottom: 12 },
  leftDesc: { color: 'rgba(250,250,248,0.5)', lineHeight: 1.75, fontSize: 'var(--text-sm)', marginBottom: 36 },
  valueProp: { display: 'flex', gap: 12, marginBottom: 14, alignItems: 'flex-start' },
  vpIcon: { width: 30, height: 30, borderRadius: '50%', background: 'rgba(181,154,106,0.12)', border: '1px solid rgba(181,154,106,0.25)', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '0.85rem', flexShrink: 0 },
  vpText: { fontSize: 'var(--text-sm)', color: 'rgba(250,250,248,0.55)', lineHeight: 1.6, paddingTop: 5 },
  formTitle: { fontSize: 'var(--text-3xl)', fontWeight: 'var(--weight-bold)', color: 'var(--color-text-primary)', letterSpacing: 'var(--tracking-tight)', marginBottom: 4 },
  formSubtitle: { color: 'var(--color-text-muted)', fontSize: 'var(--text-sm)', marginBottom: 28 },
  error: { padding: '12px 16px', background: 'var(--color-error-light)', border: '1px solid var(--color-error)', borderRadius: 'var(--radius-md)', color: 'var(--color-error)', fontSize: 'var(--text-sm)', marginBottom: 20 },
  row2: { display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 16 },
  divider: { textAlign: 'center', fontSize: 'var(--text-sm)', color: 'var(--color-text-muted)', margin: '20px 0' },
  strengthBar: { height: 4, borderRadius: 99, background: 'var(--color-stone)', overflow: 'hidden', marginTop: 6 },
  strengthFill: (s) => ({
    height: '100%', borderRadius: 99, transition: 'width 300ms, background 300ms',
    width: s === 0 ? '0%' : s === 1 ? '33%' : s === 2 ? '66%' : '100%',
    background: s === 1 ? 'var(--color-error)' : s === 2 ? 'var(--color-warning)' : s === 3 ? 'var(--color-success)' : 'transparent',
  }),
  strengthLabel: (s) => ({
    fontSize: 10, marginTop: 4,
    color: s === 1 ? 'var(--color-error)' : s === 2 ? 'var(--color-warning)' : s === 3 ? 'var(--color-success)' : 'transparent',
  }),
  successBox: {
    background: 'var(--color-gold-light)', border: '1px solid var(--color-gold)',
    borderRadius: 'var(--radius-xl)', padding: '24px', marginBottom: 20,
  },
  apiKeyDisplay: {
    fontFamily: 'var(--font-mono)', fontSize: 'var(--text-sm)', wordBreak: 'break-all',
    color: 'var(--color-gold-dark)', marginTop: 10, marginBottom: 14,
  },
};

const VALUE_PROPS = [
  { icon: '🚀', text: 'Get your API key instantly — no waitlist, no credit card.' },
  { icon: '📦', text: 'Access 32+ curated, production-ready datasets immediately.' },
  { icon: '🧠', text: 'BuildPilot generates your entire project blueprint in seconds.' },
];

function passwordStrength(pw) {
  let score = 0;
  if (pw.length >= 8) score++;
  if (/[A-Z]/.test(pw) && /[a-z]/.test(pw)) score++;
  if (/\d/.test(pw) && /[^A-Za-z0-9]/.test(pw)) score++;
  return score;
}

export default function Register() {
  const navigate = useNavigate();
  const [form, setForm] = useState({ username: '', email: '', password: '', confirm: '' });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [apiKey, setApiKey] = useState('');
  const [keyCopied, setKeyCopied] = useState(false);

  const set = (k) => (e) => setForm(f => ({ ...f, [k]: e.target.value }));
  const strength = passwordStrength(form.password);
  const strengthLabels = ['', 'Weak', 'Fair', 'Strong'];

  const register = async (e) => {
    e.preventDefault();
    if (!form.username.trim() || !form.email.trim() || !form.password) {
      setError('All fields are required.'); return;
    }
    if (form.password !== form.confirm) {
      setError('Passwords do not match.'); return;
    }
    if (strength < 2) {
      setError('Password is too weak. Include uppercase, lowercase, numbers and symbols.'); return;
    }
    setError('');
    setLoading(true);
    try {
      const res = await authApi.register(form.email.trim(), form.username.trim(), form.password);
      const d = res.data;
      auth.setTokens(d.access_token, d.refresh_token);
      auth.setUser({ email: d.email, username: d.username, id: d.user_id });
      setApiKey(d.api_key || '');
      if (!d.api_key) navigate('/dashboard');
    } catch (e) {
      setError(e.message || 'Registration failed. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const copyKey = () => { navigator.clipboard.writeText(apiKey); setKeyCopied(true); setTimeout(() => setKeyCopied(false), 1800); };

  return (
    <div style={S.page} className="page-enter">
      {/* Left */}
      <div style={S.left}>
        <div style={S.logo}>OmniCore<span style={S.logoDot}>.</span></div>
        <h2 style={S.leftTitle}>Start building with<br />real data today.</h2>
        <p style={S.leftDesc}>Create your free account and get instant access to the OmniCore platform.</p>
        {VALUE_PROPS.map((v, i) => (
          <div key={i} style={S.valueProp}>
            <div style={S.vpIcon}>{v.icon}</div>
            <div style={S.vpText}>{v.text}</div>
          </div>
        ))}
      </div>

      {/* Right */}
      <div style={S.right}>
        <div style={{ maxWidth: 440, width: '100%', margin: '0 auto' }}>
          {apiKey ? (
            /* ── API Key Success Screen ─── */
            <>
              <h1 style={S.formTitle}>You're in! 🎉</h1>
              <p style={{ color: 'var(--color-text-muted)', fontSize: 'var(--text-sm)', marginBottom: 24 }}>
                Your account is ready. Here is your API key — <strong>save it now, it won't be shown again.</strong>
              </p>
              <div style={S.successBox}>
                <div style={{ fontWeight: 'var(--weight-semibold)', color: 'var(--color-gold-dark)', marginBottom: 4 }}>⚠️ Your OmniCore API Key</div>
                <div style={S.apiKeyDisplay}>{apiKey}</div>
                <button className="btn btn-gold" style={{ width: '100%' }} onClick={copyKey}>
                  {keyCopied ? '✓ Copied to Clipboard!' : 'Copy API Key'}
                </button>
              </div>
              <p style={{ fontSize: 'var(--text-xs)', color: 'var(--color-text-muted)', marginBottom: 20 }}>
                You can generate additional API keys anytime from your Dashboard. This key is hashed and cannot be recovered.
              </p>
              <button className="btn btn-primary" style={{ width: '100%' }} onClick={() => navigate('/dashboard')}>
                Go to Dashboard →
              </button>
            </>
          ) : (
            /* ── Register Form ─── */
            <>
              <h1 style={S.formTitle}>Create account</h1>
              <p style={S.formSubtitle}>Free forever. No credit card required.</p>

              {error && <div style={S.error}>{error}</div>}

              <form onSubmit={register}>
                <div style={S.row2}>
                  <div className="form-group">
                    <label className="label" htmlFor="reg-username">Username</label>
                    <input id="reg-username" type="text" className="input" placeholder="devname"
                      value={form.username} onChange={set('username')} autoFocus autoComplete="username" />
                  </div>
                  <div className="form-group">
                    <label className="label" htmlFor="reg-email">Email</label>
                    <input id="reg-email" type="email" className="input" placeholder="you@example.com"
                      value={form.email} onChange={set('email')} autoComplete="email" />
                  </div>
                </div>
                <div className="form-group">
                  <label className="label" htmlFor="reg-password">Password</label>
                  <input id="reg-password" type="password" className="input" placeholder="Create a strong password"
                    value={form.password} onChange={set('password')} autoComplete="new-password" />
                  {form.password && (
                    <>
                      <div style={S.strengthBar}><div style={S.strengthFill(strength)} /></div>
                      <div style={S.strengthLabel(strength)}>{strengthLabels[strength]}</div>
                    </>
                  )}
                </div>
                <div className="form-group">
                  <label className="label" htmlFor="reg-confirm">Confirm Password</label>
                  <input id="reg-confirm" type="password" className="input" placeholder="Repeat password"
                    value={form.confirm} onChange={set('confirm')} autoComplete="new-password"
                    style={{ borderColor: form.confirm && form.password !== form.confirm ? 'var(--color-error)' : undefined }} />
                  {form.confirm && form.password !== form.confirm && (
                    <div style={{ fontSize: 'var(--text-xs)', color: 'var(--color-error)', marginTop: 4 }}>Passwords do not match.</div>
                  )}
                </div>

                <button id="register-submit" type="submit" className="btn btn-primary btn-lg" style={{ width: '100%' }} disabled={loading}>
                  {loading ? <><span className="spinner spinner-sm" /> Creating account…</> : 'Create Account'}
                </button>
              </form>

              <div style={S.divider}>
                Already have an account? <Link to="/login" style={{ color: 'var(--color-gold-dark)', fontWeight: 'var(--weight-medium)' }}>Sign in</Link>
              </div>
            </>
          )}
        </div>
      </div>
    </div>
  );
}
